var test=require("tape"),stringify=require("../");test("toJSON function",function(n){n.plan(1);n.equal(stringify({one:1,two:2,toJSON:function(){return{one:1}}}),'{"one":1}')}),test("toJSON returns string",function(n){n.plan(1);n.equal(stringify({one:1,two:2,toJSON:function(){return"one"}}),'"one"')}),test("toJSON returns array",function(n){n.plan(1);n.equal(stringify({one:1,two:2,toJSON:function(){return["one"]}}),'["one"]')});